#include <iostream>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    // A power of two is positive and has exactly one bit set.
    // (n & (n - 1)) == 0 is the classic check for power of two (n > 0).
    if (n > 0 && (n & (n - 1)) == 0)
        cout << "YES\n";
    else
        cout << "NO\n";

    return 0;
}
